/**
 * @param {number[]} nums
 * @return {number}
 */
function solve(nums) {
    const n = nums.length;
    const sortedNums = [...nums].sort((a, b) => a - b);

    /**
     * Checks if an array (or sub-array) can be sorted by cyclic shifts.
     * An array can be sorted by cyclic shifts if and only if it is a cyclic permutation
     * of the sorted version of itself.
     * Since we are dealing with contiguous segments of the target sorted array,
     * if the elements within a segment match the expected elements from the sorted array,
     * the only requirement is that the set of elements is correct.
     * However, the problem states "independent cyclic shift".
     * A sequence can be sorted by cyclic shift if and only if it is a cyclic shift of the sorted sequence.
     * For a segment of length k, let S be the sorted version of the segment. The original segment
     * must be a cyclic permutation of S.
     * A simpler condition for an array A of length k to be transformable into its sorted version S
     * via cyclic shifts is that A must be a cyclic shift of S.
     * This means A must be a rotation of S.
     * Example: S = [1, 2, 3]. Rotations: [1, 2, 3], [2, 3, 1], [3, 1, 2].
     *
     * @param {number[]} segment The segment of length k.
     * @param {number[]} targetSorted The full sorted array.
     * @param {number} start The starting index of the segment in the original array (and sorted array).
     * @param {number} k The length of the segment.
     * @returns {boolean} True if the segment can be cyclically shifted to match the sorted order.
     */
    function canSortSegment(segment, start, k) {
        if (k === 1) return false; // Based on Example 1's explanation for k=1.

        // 1. Get the target sorted segment corresponding to this position
        const targetSegment = sortedNums.slice(start, start + k);

        // 2. Check if the elements are the same (necessary condition)
        const segmentSorted = [...segment].sort((a, b) => a - b);
        for (let i = 0; i < k; i++) {
            if (segmentSorted[i] !== targetSegment[i]) {
                return false;
            }
        }

        // 3. Check if 'segment' is a cyclic permutation of 'targetSegment'
        // Concatenate the target segment with itself: T' = targetSegment + targetSegment
        const doubledTarget = [...targetSegment, ...targetSegment];

        // Convert arrays to strings for easy substring search (or use string matching logic)
        // Since numbers can be multi-digit, a simple string join might fail if not careful.
        // Since all numbers are positive integers, we can check the rotation property directly.

        // A sequence A is a rotation of B if A is a subsequence of B+B of length |B|.
        let isRotation = false;
        for (let i = 0; i < k; i++) {
            // Check if segment matches the target starting at index i in the doubled target
            let match = true;
            for (let j = 0; j < k; j++) {
                if (segment[j] !== doubledTarget[i + j]) {
                    match = false;
                    break;
                }
            }
            if (match) {
                isRotation = true;
                break;
            }
        }

        return isRotation;
    }

    // Find all divisors k of n
    const divisors = [];
    for (let k = 1; k * k <= n; k++) {
        if (n % k === 0) {
            divisors.push(k);
            if (k * k !== n) {
                divisors.push(n / k);
            }
        }
    }

    let sumOfK = 0;

    for (const k of divisors) {
        if (k === 1) {
            // As per Example 1 explanation, k=1 is never sortable unless n=1, but constraints say n>=1.
            // If n=1, k=1. nums=[x]. Already sorted. But the explanation implies k=1 fails generally.
            // Let's strictly follow the logic derived from the problem description:
            // "Independent cyclic shift". For k=1, segment is [x]. Only 1 rotation: [x]. 
            // If the target segment is [x], it matches. But Example 1 says k=1 fails for [3,1,2] (n=3).
            // We adhere to the observation from Example 1: k=1 is not "sortable" in the required sense.
            continue;
        }

        let allSegmentsSortable = true;
        const numSegments = n / k;

        // Iterate through each segment
        for (let i = 0; i < numSegments; i++) {
            const start = i * k;
            const segment = nums.slice(start, start + k);

            // The target segment for this position in the sorted array is sortedNums[start:start+k]
            if (!canSortSegment(segment, start, k)) {
                allSegmentsSortable = false;
                break;
            }
        }

        if (allSegmentsSortable) {
            sumOfK += k;
        }
    }

    return sumOfK;
}

